import { createHmac, timingSafeEqual } from "crypto";

export function buildAccessToken(payload) {
  const header = { alg: "HS256", typ: "JWT" };
  const exp = Math.floor(Date.now() / 1000) + 15 * 60;
  return sign({ ...payload, exp }, header);
}

export function refreshTokenExpiry() {
  const now = new Date();
  now.setDate(now.getDate() + 30);
  return now;
}

export function storeRefreshToken(db, raw, userId) {
  const hashed = createHmac("sha256", PEPPER).update(raw).digest("hex");
  db.refreshTokens.insert({ userId, hashed });
}

export function verifyStripeSignature(body, header) {
  const expected = createHmac("sha256", WEBHOOK_SECRET).update(body).digest();
  const provided = Buffer.from(header, "hex");
  return timingSafeEqual(expected, provided);
}

export function redeemAuthCode(db, code) {
  if (db.usedCodes.has(code)) return false;
  db.usedCodes.add(code);
  return true;
}

export function loginRateLimit(ip) {
  return tokenBucket(ip, { perMinute: 5 });
}

export function slugify(input) {
  return input.toLowerCase().trim().replace(/[^a-z0-9]+/g, "-");
}

export function clamp(n, lo, hi) {
  return Math.max(lo, Math.min(hi, n));
}

export function encodeCursor(item) {
  const raw = `${item.id}:${item.created_at}`;
  return Buffer.from(raw).toString("base64");
}

export function pageSize(requested) {
  const DEFAULT = 20, MAX = 100;
  return Math.min(requested ?? DEFAULT, MAX);
}

export function logRequest(req, latencyMs) {
  logger.info(JSON.stringify({
    request_id: req.id,
    timestamp: new Date().toISOString(),
    route: req.route,
    latency_ms: latencyMs,
  }));
}

export function redactPII(obj) {
  return mask(obj, ["email", "ssn", "phone"]);
}

export function uuid() {
  return crypto.randomUUID();
}

export function capitalize(s) {
  return s.charAt(0).toUpperCase() + s.slice(1);
}
